import React from 'react';
import clsx from 'clsx';
import type { InputProps } from './Input';
import { Input } from './Input';
import { useComponentSize, useInputGroupSize, useCssScope, useLocale } from '../config-provider/hooks';
import SearchOutlineOutlined from '@universe-design/icons-react/SearchOutlineOutlined';
import type { ElementOf } from '../util';
import { getDefaultSizeAbbr } from '../util';

import './style';

const SearchShapesEnum = ['round', 'square'] as const;
export type Searchhape = ElementOf<typeof SearchShapesEnum>;

/**
 * 用于搜索输入框 `Input.Search`
 * @public
 */
export interface SearchProps extends InputProps {
  /**
   * 搜索框的形状
   * @defaultValue `round`
   */
  shape?: Searchhape;
}

export const Search = React.forwardRef<HTMLInputElement, SearchProps>((props, ref) => {
  const {
    global: { search },
  } = useLocale();
  const { shape = 'round', size: customerSize, placeholder = search, className, ...restProps } = props;

  const cssScope = useCssScope('search');
  const configSize = useComponentSize();
  const inputGroupSize = useInputGroupSize();
  const size = customerSize || inputGroupSize || configSize;
  const usedSize = getDefaultSizeAbbr(size);

  const cls = clsx(
    cssScope(),
    {
      [cssScope(`--size-${usedSize}`)]: usedSize,
      [cssScope(`--shape-${shape}`)]: shape,
    },
    className,
  );

  return (
    <Input
      ref={ref}
      className={cls}
      size={size}
      placeholder={placeholder}
      prefix={<SearchOutlineOutlined />}
      {...restProps}
    />
  );
});
if (__DEV__) {
  Search.displayName = 'Search';
}
